1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE = 25;
3	const BLOCK_OF_THREE_BASE = 60;
4	
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	
17	type Item = {
18	  type: string;
19	  material?: string;
20	  enchantment?: number;
21	  cursed?: boolean;
22	};
23	type QuoteStep = { op: "quote"; items: Item[] };
24	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
25	type QuoteResult = { premium: number };
26	type ScenarioResult = { results: QuoteResult[] };
27	
28	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
29	
30	const countByType = (items: Item[]): Map<string, number> => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const componentTypeBase = (count: number): number =>
39	  count === 3 ? BLOCK_OF_THREE_BASE : count * COMPONENT_BASE;
40	
41	const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
42	
43	const mainItemsBase = (items: Item[]): number =>
44	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + mainItemBase(item), 0);
45	
46	const componentsBase = (items: Item[]): number => {
47	  const counts = countByType(items.filter(isComponent));
48	  return [...counts.values()].reduce(
49	    (sum, count) => sum + componentTypeBase(count),
50	    0,
51	  );
52	};
53	
54	const itemSurcharges = (items: Item[]): number =>
55	  items
56	    .filter((item) => !isComponent(item))
57	    .reduce((sum, item) => sum + (item.cursed ? mainItemBase(item) * CURSED_SURCHARGE_RATE : 0), 0);
58	
59	const policyBase = (items: Item[]): number => mainItemsBase(items) + componentsBase(items);
60	
61	const quote = (step: QuoteStep): QuoteResult => {
62	  const base = policyBase(step.items);
63	  const surcharges = itemSurcharges(step.items);
64	  const firstInsurance = base * FIRST_INSURANCE_RATE;
65	  const total = base + surcharges + firstInsurance + PROCESSING_FEE;
66	  return { premium: Math.ceil(total) };
67	};
68	
69	export const runScenario = (scenario: Scenario): ScenarioResult => ({
70	  results: scenario.steps.map(quote),
71	});
